INSERT INTO public.photos VALUES (23473, 'P.â”¬â•‘ del General Mola c.1960', 'Imagen capturada en el paseo del General Mola y centrada en el tramo de viviendas del lado de los pares que llegaba hasta la calle de Juan Pablo Bonet (al fondo, a la izquierda). Se trata de un tardâ”œÂ¡o trâ”œÂ¡o de hotelitos o viviendas unifamiliares construidas en el paseo de Sagasta sobre una triangular parcela propiedad de Balbina Palomar. A la derecha, con llamativo remate en esquinero torreâ”œâ”‚n, el nâ”œâ•‘mero 26 triplicado, que habâ”œÂ¡a sido proyectado a finales de los aâ”œâ–’os veinte por el arquitecto Teodoro Râ”œÂ¡os Balaguer para Maximiano Pâ”œÂ®rez Forniâ”œÂ®s. A su izquierda, formalmente muy similar, la casa de Pellejero en el nâ”¬â•‘ 26 cuadruplicado Estas viviendas de la imagen fueron derribadas al principio de la prodigiosa dâ”œÂ®cada de los setenta, y en su lugar fue construido un moderno y vertical bloque de viviendas. Fuente visual: www.rafaelcastillejo.com/', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64030400, -0.88668300, '0101000020E6100000D369DD06B55FECBFBEBF417BF5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31693841768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31693841768.webp', 'https://www.flickr.com/photos/zaragozaantigua/31693841768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24109, 'Ensanche Miralbueno 1937', 'Imagen capturada durante la solemne bendiciâ”œâ”‚n de los terrenos y colocaciâ”œâ”‚n de la primera piedra del Grupo de 27 Casas Baratas que la Central Obrera Nacionalsindicalista (CONS) iba a construir en la zona del Ensanche de Miralbueno, junto a la Gran Vâ”œÂ¡a. Oficia el ritual de bendecir los terrenos el sacerdote Cristâ”œâ”‚bal Mateo, acompaâ”œâ–’ado en primera fila por Jesâ”œâ•‘s Muro, Jefe territorial de Falange Espaâ”œâ–’ola, y del teniente coronel Buendâ”œÂ¡a, en representaciâ”œâ”‚n de la Quinta Divisiâ”œâ”‚n. Asistieron tambiâ”œÂ®n varios representantes del Ayuntamiento, de la Caja de Previsiâ”œâ”‚n Social de Aragâ”œâ”‚n, y Josâ”œÂ® Sinuâ”œÂ®s, director de la Caja de Ahorros y Monte de Piedad. Completan el conjunto otros jefes locales de Falange, "Flechas", "gastadores", "camaradas" de Segunda Lâ”œÂ¡nea, empresarios y obreros. Ante ellos, la primera piedra a colocar, que portaba la informativa inscripciâ”œâ”‚n "â”¬Ă­Arriba Espaâ”œâ–’a!" y la fecha del "11 de abril de 1937". Estas viviendas originalmente formaban parte de los terrenos de la Cooperativa de Casas Baratas Pablo Iglesias, que como es natural y tras el 18 de julio de 1936 fueron râ”œĂ­pidamente anuladas y concedidas a la CONS. Estas casas perduran y se localizan entre las calles de Ram de Viu, Mariano Supervâ”œÂ¡a y Francisco de la Ripa, en sus tramos comprendidos entre las calles de Cosme Blasco y Agustâ”œÂ¡n de Quinto.', 1937, 1937, 1937, 'Anos 30', 'UNIVERSIDAD', 41.63982100, -0.89259600, '0101000020E6100000164B917C2590ECBFA2258FA7E5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51867277272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51867277272.webp', 'https://www.flickr.com/photos/zaragozaantigua/51867277272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24456, 'C.â”¬â•‘ del Sâ”œĂ­bado 1970', 'Ramal del Camino del Sâ”œĂ­bado inmediato a la trinchera del râ”œÂ¡o Huerva, entre la nueva "Avenida de Goya", y la calle Juan Pablo Bonet. La cercanâ”œÂ¡a del râ”œÂ¡o habâ”œÂ¡a propiciado la implantaciâ”œâ”‚n en esta zona de numerosas pequeâ”œâ–’as industrias de transformaciâ”œâ”‚n, como calzado, gâ”œÂ®neros de punto, curtidos, e incluso una fâ”œĂ­brica de bicicletas. La urbanizaciâ”œâ”‚n de la zona se acelerâ”œâ”‚ tras el cubrimiento de las vâ”œÂ¡as del ferrocarril de Madrid a Barcelona, a comienzos de los aâ”œâ–’os 60. Hasta entonces, las viviendas en la zona eran escasas, y de tipologâ”œÂ¡a tradicional (parcelas). En la imagen, capturada durante la urbanizaciâ”œâ”‚n de la zona de las calles de Benavente, del Arzobispo Domenech y de Moncasi, estado del antiguo camino del Sâ”œĂ­bado entre el puente "de la Vâ”œÂ¡a Transversal" (oficialmente del "Emperador Augusto", y conocido como "de los Gitanos"), que queda a la espalda, y los bloques de viviendas de los nâ”œâ•‘meros 8 y 9 de la actual calle Genoveva Torres Morales. El "1500", aparcado junto al portal del nâ”¬â•‘ 8. A continuaciâ”œâ”‚n, muros que delimitaban solares, un terroso camino que conectaba sinuosamente con la calle Benavente y la avenida de Goya, y antiguas construcciones industriales junto al râ”œÂ¡o. Precisamente, a la izquierda, antigua fâ”œĂ­brica de curtidos de la "Sociedad La Progresiva de expendedores de carnes", proyectada por Miguel â”œĂ¼ngel Navarro en 1916. Como todos las instalaciones industriosas que jalonaban el Huerva en su tramo urbano, utilizaba el râ”œÂ¡o como cloaca o vertedero de residuos, ya que la energâ”œÂ¡a motriz era elâ”œÂ®ctrica. Fue luego derribada.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64109600, -0.88942000, '0101000020E6100000F5108DEE2076ECBF57CC086F0FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19206356293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19206356293.webp', 'https://www.flickr.com/photos/zaragozaantigua/19206356293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24461, 'Tudor 1930', 'Imagen de "La Pilar", o fâ”œĂ­brica de la Sociedad Espaâ”œâ–’ola del Acumulador Tudor en su ubicaciâ”œâ”‚n entre el Camino de las Torres y el de las Alcachoferas. Instalada en 1898, su buena marcha econâ”œâ”‚mica posibilitâ”œâ”‚ que en 1916 Teodoro Râ”œÂ¡os diseâ”œâ–’ara unos nuevos pabellones. El frontal de la fâ”œĂ­brica daba a la subida a Torrero. A la izquierda, el Camino de las Torres. A la derecha, el Camino de las Alcachoferas. Al fondo, tras los â”œĂ­rboles, los campos de Miraflores. La imagen se ha capturado, posiblemente, desde la casa del escultor Palao. Fuente visual: AVV. San Josâ”œÂ®.', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63951700, -0.88595500, '0101000020E61000002849D74CBE59ECBF361E6CB1DBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19778469664.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19778469664.webp', 'https://www.flickr.com/photos/zaragozaantigua/19778469664/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24874, 'Casa Faci 1966', '1966. Foto Pomarâ”œâ”‚n. Cruce de Paseo Mola con el arranque del Camino de las Torres (al fondo, a la derecha). Desde un balcâ”œâ”‚n de la sensacionalista y fraudulenta "Casa del Duende", imagen de "Casa Faci", de Regino Borobio Ojeda, construida en 1925, y derribada en 1971.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64011000, -0.88623900, '0101000020E610000062122EE4115CECBFD9EBDD1FEFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14741498557.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14741498557.webp', 'https://www.flickr.com/photos/zaragozaantigua/14741498557/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24892, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1943', 'Imagen de la "Casa Luis Gabâ”œĂ­s", diseâ”œâ–’ada por Regino y Josâ”œÂ® Borobio y construida en el Paseo de Ruiseâ”œâ–’ores nâ”¬â•‘ 2, en la manzanita que daba a la empinada calle Sevilla. La fachada principal y la puerta de acceso daban, precisamente, a esta calle. Era una vivienda unifamiliar de tres pisos (sâ”œâ”‚tano, bajo y principal), en el estilo regionalista-aragonesista imperante en el nuevo Râ”œÂ®gimen franquista. Peculiar era el remate en torreâ”œâ”‚n, personalizado a esta vivienda por ser la primera de la calle, con estratâ”œÂ®gica visual. En 1976 fue piqueteada, y en su solar se levantâ”œâ”‚ la nueva sede del Colegio Oficial de Mâ”œÂ®dicos de Zaragoza. Fuente visual: Archivo Borobio, en Mâ”œâ”‚nica Vâ”œĂ­zquez Astorga, "Recorrido por el pasado de una zona urbana residencial: el paseo de Ruiseâ”œâ–’ores de Zaragoza", Artigrama nâ”¬â•‘ 22, 2007.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.63829800, -0.88709200, '0101000020E6100000286211C30E63ECBF158DB5BFB3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15155482223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15155482223.webp', 'https://www.flickr.com/photos/zaragozaantigua/15155482223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24893, 'Plaza de San Francisco 1969', 'Archivo Histâ”œâ”‚rico Municipal. Gerardo Sancho Ramo. 14/12/1969. El 15 de octubre de 1969 fue inaugurado el Monumento a Fernando el Catâ”œâ”‚lico de la Plaza de San Francisco, siendo Cesâ”œĂ­reo Alierta el alcalde la ciudad. Obra de Juan de â”œĂ¼valos, estâ”œĂ­ caracterizada por el monumentalismo figurativo con que el Râ”œÂ®gimen pretendâ”œÂ¡a entroncar su legitimidad histâ”œâ”‚rica en la Espaâ”œâ–’a de los Reyes Catâ”œâ”‚licos. Este escultor habâ”œÂ¡a realizado antes varios bultos redondos en el Valle de los Caâ”œÂ¡dos (fascistas). En la imagen, la escultura del Catâ”œâ”‚lico con un par de pintadas subversivas en el pedestal câ”œâ•‘bico, emborronadas apresuradamente antes de ser eliminadas. En la inferior puede leerse "LIBERTAD".', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64093700, -0.89482600, '0101000020E61000002F89B3226AA2ECBFEFE53E390AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15202909412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15202909412.webp', 'https://www.flickr.com/photos/zaragozaantigua/15202909412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24949, 'Calle Supervâ”œÂ¡a 1973', 'Imagen parcial de la antigua vivienda unifamiliar, u hotel, nâ”¬â•‘ 32 edificada a finales de 1929 en la manzana 48 del proyecto de las Casas Baratas del ensanche de Miralbueno, junto al râ”œÂ¡o Huerva, con diseâ”œâ–’o de Miguel â”œĂ¼ngel Navarro, en un nuevo vial luego denominado calle Supervâ”œÂ¡a (a la izquierda), vistosamente esquinero con la nueva calle de Ram de Viu (hacia la derecha), en airoso estilo eclâ”œÂ®ctico y contrastadas trazas regionalistas. En el momento de realizar al captura, esta casa era "Villa Marâ”œÂ¡a Luisa", sita en la calle de Supervâ”œÂ¡a nâ”¬â•‘ 56, y el ataâ”œâ•‘d de primer tâ”œÂ®rmino contiene los restos mortales de Luisa Lara Faguas, reciâ”œÂ®n fallecida, camino de la iglesia parroquial de San Juan de la Cruz para su funeral "corpore insepulto". Desde 1981, este provinciano edificio, junto con la mayor parte de sus convecinos de los tiempos de Miralbueno, fueron derribados para ser sustituidos por los modernos bloques levantados en su lugar. 42 arquitectos solicitaron declarar este sector de las Casas Baratas como conjunto histâ”œâ”‚rico-artâ”œÂ¡stico, pero el Ayuntamiento no tuvo voluntad polâ”œÂ¡tica para intentarlo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63848400, -0.89439700, '0101000020E6100000137F1475E69EECBF7782FDD7B9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32828512391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32828512391.webp', 'https://www.flickr.com/photos/zaragozaantigua/32828512391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24983, 'Pignatelli 1904', 'Foto: Lete. Inauguraciâ”œâ”‚n del nuevo emplazamiento de la estatua de Ramâ”œâ”‚n Pignatelli "en las inmediaciones del Canal". Este espacio serâ”œĂ­ denominado despuâ”œÂ®s "parque Pignatelli". El monumento habâ”œÂ¡a estado levantado en la glorieta de Pignatelli, luego plaza de Aragâ”œâ”‚n, desde 1859. A partir de octubre de 1904 fue sustituido por el actual, dedicado al Justiciazgo. Fuente: Diario ABC, 27-10-1904.', 1904, 1904, 1904, 'Anos 1900', 'UNIVERSIDAD', 41.63689100, -0.88506400, '0101000020E610000001BEDBBC7152ECBFF10EF0A485D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26093682588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26093682588.webp', 'https://www.flickr.com/photos/zaragozaantigua/26093682588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24992, 'P.â”¬â•‘ del Siglo XX 1904', 'La inauguraciâ”œâ”‚n de la estatua de Ramâ”œâ”‚n Pignatelli en su nueva ubicaciâ”œâ”‚n en el desmonte junto al paseo del Siglo XX fue uno de los eventos destacados de las Fiestas del Pilar de ese aâ”œâ–’o. Su original emplazamiento en la plaza de Aragâ”œâ”‚n habâ”œÂ¡a sido ocupado por el moderno Monumento al Justiciazgo, un simbâ”œâ”‚lico cambio con el que las elites locales mostraban sus preferencias por los mitos româ”œĂ­nticos y conservadores de siglos pretâ”œÂ®ritos, antes que por los logros materiales de la luz de la Ilustraciâ”œâ”‚n.', 1904, 1904, 1904, 'Anos 1900', 'UNIVERSIDAD', 41.63688700, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFB01F628385D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50344646553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50344646553.webp', 'https://www.flickr.com/photos/zaragozaantigua/50344646553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24998, 'Casa de Pedro Hernâ”œĂ­ndez Luna 1931', 'Foto Marâ”œÂ¡n Chivite, 1931. Paseo de Ruiseâ”œâ–’ores, 20. Actualmente Clâ”œÂ¡nica del Pilar. Edificio racionalista de Regino Borobio, 1931. Fuente visual: "Una mirada a travâ”œÂ®s de la arquitectura: Regino y Josâ”œÂ® Borobio Ojeda", Daniel Estabâ”œÂ®n Boldova, 2013.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63726300, -0.88914100, '0101000020E61000002C0C91D3D773ECBFB5F97FD591D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14770916580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14770916580.webp', 'https://www.flickr.com/photos/zaragozaantigua/14770916580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25001, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1930', 'Alberto Casaâ”œâ–’al Shakery era un gaditano nato naturalizado zaragozano. De formaciâ”œâ”‚n cientâ”œÂ¡fica, inclinâ”œâ”‚ aficiâ”œâ”‚n por los mitos y leyendas del costumbrismo y folklore româ”œĂ­ntico del lugar, y se convirtiâ”œâ”‚ en "el poeta" de lo baturro como constructo identitario del "ser aragonâ”œÂ®s". Sus obras sobre este tema, y una personalidad abierta, empâ”œĂ­tica y humorâ”œÂ¡stica, le alzaron como referente social popularâ”œÂ¡simo: recibiâ”œâ”‚ el tâ”œÂ¡tulo de "Hijo Adoptivo" y la Medalla de Oro de la ciudad, y una iniciativa social impulsada por el Ateneo Zaragozano le regalâ”œâ”‚ por suscripciâ”œâ”‚n popular una casa, llamada "del Poeta", para â”œÂ®l, su compaâ”œâ–’era, y las tres hijas y cuatro hijos comunes. Fue levantada en terrenos municipales inmediatos a los Depâ”œâ”‚sitos de Agua, en el Paseo de los Ruiseâ”œâ–’ores, en formas y estilo mucho mâ”œĂ­s modestos que los de las cercanas y renombradas residencias burguesas de la zona. Allâ”œÂ¡ vivirâ”œÂ¡a hasta 1943, aâ”œâ–’o de su muerte. La vivienda fue pasando de unas manos particulares a otras, y por aquellas cosas de los trâ”œĂ­mites, y de las cosas de esta ciudad, llegâ”œâ”‚ al siglo XXI sin ninguna figura de protecciâ”œâ”‚n o catalogaciâ”œâ”‚n pâ”œâ•‘blica, aun formando parte de la interesante nâ”œâ”‚mina de edificios y construcciones que jalonaban esa zona. Asâ”œÂ¡ las cosas, en 2004 "La Casa del Poeta" fue piqueteada, y en su lugar se levantaron unas mejor aprovechadas viviendas particulares. En la imagen, aspecto de la "Casa del Poeta" situada justo en la esquina del Paseo de los Ruiseâ”œâ–’ores (izquierda), y un vial que en 1950 recibiâ”œâ”‚ el nombre de "Santiago Guallar" (derecha). Los muros de contenciâ”œâ”‚n salvan el enorme desnivel de la zona, una de las "terrazas" de Cuâ”œÂ®llar. Justo detrâ”œĂ­s estâ”œĂ­ el barbecho urbanâ”œÂ¡stico expectante de los Depâ”œâ”‚sitos de Agua. Fuente: Foto Martâ”œÂ¡nez (Mundo Grâ”œĂ­fico, noviembre 1930)', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63721500, -0.88849700, '0101000020E6100000F702B342916EECBFA4C2D84290D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17112763737.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17112763737.webp', 'https://www.flickr.com/photos/zaragozaantigua/17112763737/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25009, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1930', 'Imagen de la soleada terraza del estiloso Restaurant Ruiseâ”œâ–’ores, ubicado cerca del arranque del paseo del mismo nombre, "a muy pocos metros del tranvâ”œÂ¡a de Torrero", como rezaba la publicidad de la â”œÂ®poca, dado que esta zona seguâ”œÂ¡a pareciendo un poco a desmano de la sedetana urbe. La frondosa vegetaciâ”œâ”‚n indica el exuberante arbolado del paseo, al que se le aâ”œâ–’adâ”œÂ¡an en este caso los jardines de la casa del nâ”¬â•‘ 12, cuya fachada principal es parcialmente visible en un oportuno claro. Al fondo, los â”œâ•‘ltimos edificios del paseo de Sagasta, y el arranque de la avenida del Siglo XX. A la derecha, el comedor con servicio diario de menâ”œâ•‘ y a la carta, y vistas mâ”œĂ­s que interesantes a la ciudad. Fuente visual: periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63740000, -0.88797200, '0101000020E610000054707841446AECBF363CBD5296D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32432959341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32432959341.webp', 'https://www.flickr.com/photos/zaragozaantigua/32432959341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25014, 'Avenida de la Repâ”œâ•‘blica 1934', 'Tarjeta Postal de la "Avenida de la Repâ”œâ•‘blica". Comenzaba en la Plaza de Aragâ”œâ”‚n (al fondo de la imagen), hasta el punto en que estâ”œĂ­ hecha la foto,en la confluencia con el Camino de las Torres (hacia la derecha), con el Camino del Sâ”œĂ­bado y Gascâ”œâ”‚n de Gotor (hacia la izquierda). A partir de este punto, comenzaba la Avenida del Siglo XXI, que llegaba hasta la Playa de Torrero. Ninguno de los edificios de la izquierda (los nâ”œâ•‘meros pares) sobreviven. De los de la derecha (nâ”œâ•‘meros impares), alguno. La imagen se corresponde con el estado de este tramo del antiguo paseo de Sagasta capturado antes de 1928.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63974100, -0.88644800, '0101000020E6100000F3583332C85DECBF86747808E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14674788707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14674788707.webp', 'https://www.flickr.com/photos/zaragozaantigua/14674788707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25023, 'Laboratorios ULTA 1977', 'La huelga laboral por motivos econâ”œâ”‚micos en los Laboratorios Universal Lucha Terapâ”œÂ®utica Antiinfecciosa, Ulta, desvelâ”œâ”‚ el funcionamiento de una prâ”œâ”‚spera empresa hasta entonces considerada modâ”œÂ®lica, basada en el paternalismo empresarial y en unas buenas conexiones con el poder polâ”œÂ¡tico del Râ”œÂ®gimen. En Zaragoza fabricaba alimentos infantiles con el prestigio publicitario que le otorgaba la vinculaciâ”œâ”‚n con una empresa alemana tapadera, la Deutsche Ulta; con la Fundaciâ”œâ”‚n Fernando Cuenca Villoro y a travâ”œÂ®s del Instituto de Investigaciâ”œâ”‚n Bioquâ”œÂ¡mica y de Nutriciâ”œâ”‚n Don Juan Carlos I, sin investigaciones tangibles; y con la utilizaciâ”œâ”‚n de la imagen del doctor Grande Coviâ”œĂ­n, destacado de la Fundaciâ”œâ”‚n. En la imagen, manifestaciâ”œâ”‚n de trabajadores y trabajadoras de Laboratorios ULTA en las inmediaciones de la empresa, al fondo, en la calle de Juan Pablo Bonet.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63997500, -0.88735100, '0101000020E61000002A55A2EC2D65ECBFF9A067B3EAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15603958197.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15603958197.webp', 'https://www.flickr.com/photos/zaragozaantigua/15603958197/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25032, 'Calle Juan Pablo Bonet 1934', 'El alcalde de Zaragoza, Miguel Lâ”œâ”‚pez de Gera, inaugura la placa alusiva al nuevo nombre de la Ronda de Circunvalaciâ”œâ”‚n o Vâ”œÂ¡a Transversal: Juan Pablo Bonet. A la izquierda, bar esquinero con la calle de Anselmo Gascâ”œâ”‚n de Gotor. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31376048700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31376048700.webp', 'https://www.flickr.com/photos/zaragozaantigua/31376048700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25039, 'Gascâ”œâ”‚n de Gotor 1935', 'Imagen de la moderna y reciente fachada de acceso a la Tintorerâ”œÂ¡a Imperial de Jaime Masip, sita en el nâ”¬â•‘ 10 de la calle de Gascâ”œâ”‚n de Gotor. Ante ella posa Maruja Soria, almuniense elegida Miss Aragâ”œâ”‚n. Junto a ella, el referido Masip, que contaba con sucursales de esta casa en Don Jaime I, Mâ”œÂ®ndez Nâ”œâ•‘â”œâ–’ez, y Torre Nueva. Este tipo de comerciales protagonizados por la Miss del momento, eran habituales en la publicidad de la â”œÂ®poca. En la cristalera del edificio se reflejan las vallas de obra del edificio en construcciâ”œâ”‚n del nâ”¬â•‘ 9, al otro lado de la calle. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63955900, -0.88756300, '0101000020E6100000FF774485EA66ECBF656EBE11DDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35737164503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35737164503.webp', 'https://www.flickr.com/photos/zaragozaantigua/35737164503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25044, 'Avenida de la Repâ”œâ•‘blica/del General Mola 1937', 'Imagen capturada, posiblemente, desde las alturas de la modernista Casa de Palao, en el arranque de la avenida del Siglo XX, con una recurrente vista de la avenida de la Repâ”œâ•‘blica en su tramo inmediato al final, por la derecha, del camino de las Torres. Signo de los tiempos en esta tarjeta postal, destaca el arsesanal cambiazo de râ”œâ”‚tulo de la misma, de "Avenida de la Repâ”œâ•‘blica", a "Avenida del General Mola", de resultas de la inmediata modificaciâ”œâ”‚n del nomenclâ”œĂ­tor asociado, de alguna forma, a personas, ideas, valores, fechas y conmemoraciones vinculadas con la Segunda Repâ”œâ•‘blica Espaâ”œâ–’ola, realizada por la nueva corporaciâ”œâ”‚n municipal nacionalista impuesta que asumiâ”œâ”‚ el gobierno municipal tras el triunfo del militar golpe de Estado del 19 de julio de 1936. En un primer momento, y hasta la realizaciâ”œâ”‚n de nuevas imâ”œĂ­genes para iluminar postales tras la guerra, las imâ”œĂ­genes anteriores fueron "recicladas", tal que esta. Ademâ”œĂ­s, la imagen se corresponde con el aspecto de este tramo del paseo anterior a la dâ”œÂ®cada de los aâ”œâ–’os 30.', 1937, 1937, 1937, 'Anos 30', 'UNIVERSIDAD', 41.64003000, -0.88644800, '0101000020E6100000F3583332C85DECBFBD3AC780ECD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49219518067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49219518067.webp', 'https://www.flickr.com/photos/zaragozaantigua/49219518067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25049, 'Calle de Gascâ”œâ”‚n de Gotor, 1934', 'Un par de guardias del Cuerpo de Seguridad y Asalto abren la hornilla de la cocina econâ”œâ”‚mica de la que sale una extraâ”œâ–’a voz de hombre en el segundo piso derecha del nâ”¬â•‘ 2 de la calle de Gascâ”œâ”‚n de Gotor. El fantâ”œĂ­stico episodio, bautizado "el duende de la hornilla" o "el duende de Zaragoza", impacta en la opiniâ”œâ”‚n pâ”œâ•‘blica del momento.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63987700, -0.88725300, '0101000020E610000075E448676064ECBF363B527DE7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51098766554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51098766554.webp', 'https://www.flickr.com/photos/zaragozaantigua/51098766554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25577, 'Juan Pablo Bonet 1962', 'John "Ganso" Kovatch, militar del ejâ”œÂ®rcito de los EE.UU de Norteamâ”œÂ®rica destinado en la Base Aâ”œÂ®rea de Zaragoza, haciendo turismo en la ciudad. En la imagen, el chaflâ”œĂ­n del edificio de la calle de Juan Pablo Bonet 25, en el que residiâ”œâ”‚ una temporada, de alquiler, junto al antiguo camino del Sâ”œĂ­bado (a la derecha), entonces lleno de instalaciones industriosas, al Huerva, y al "puente de los Gitanos" (antiguo puente de la Vâ”œÂ¡a Transversal). El "coche del pueblo" diseâ”œâ–’ado por Ferdinand Posche y Adolfo Hitler, mirando hacia el paseo del General Mola.', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.64057500, -0.88915200, '0101000020E6100000278925E5EE73ECBF4ED1915CFED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15110849157.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15110849157.webp', 'https://www.flickr.com/photos/zaragozaantigua/15110849157/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25586, 'Calle Viva Espaâ”œâ–’a 1954', 'Vista de la calle de Viva Espaâ”œâ–’a engalanada por celebraciâ”œâ”‚n de fiestas, en 1954. Vemos el â”œâ•‘ltimo tramo, sin salida al fondo, vallado por ser acceso al râ”œÂ¡o Huerva. Fuente: www.facebook.com/photo.php?fbid=10203686625306944&set...', 1954, 1954, 1954, 'Anos 50', 'UNIVERSIDAD', 41.63968400, -0.89035400, '0101000020E6100000ED9BFBABC77DECBF22E3512AE1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21279479756.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21279479756.webp', 'https://www.flickr.com/photos/zaragozaantigua/21279479756/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25607, 'Carmelitas Descalzos 1931', 'En 1929 se puso la primera piedra del nuevo Convento e Iglesia de los Carmelitas Descalzos, al lado de la proyectada plaza de Espaâ”œâ–’a y la Gran Vâ”œÂ¡a zaragozana, junto al antiguo camino de Los Cubos, entre campos de maâ”œÂ¡z. El proyecto llevaba la firma de Secundino Zuazo, y una elevada torre era elemento destacado de la nueva construcciâ”œâ”‚n, pensada para una comunidad de 40 carmelitas descalzos, que se vendrâ”œÂ¡an a esta ubicaciâ”œâ”‚n desde la provisional de Delicias. A la ceremonia asistiâ”œâ”‚ el arzobispo y las primeras autoridades militares y civiles (Capitâ”œĂ­n General, Gobernador Civil, Alcalde...) Circunstancias histâ”œâ”‚ricas torcieron el asunto, y el proyectado convento fue militarizado por los golpistas tras el 18 de julio de 1936, que lo utilizaron aprovechando la torre como centro de transmisiones. En 1943 el edificio terminâ”œâ”‚ en manos de La Salle, que lo reconvirtiâ”œâ”‚ en colegio, hasta hoy. Los Carmelitas Descalzos se buscaron otro lugar. No muy lejos, en San Juan de la Cruz, y al aâ”œâ–’o siguiente, ya estaban instalados. En la imagen, aspecto de las obras en 1931, vistas desde la plaza de Espaâ”œâ–’a. Fuente: "Los Carmelitas Descalzos en Zaragoza", Fray Valentâ”œÂ¡n de la Cruz, 1995.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.64017400, -0.89340000, '0101000020E610000082E2C798BB96ECBFF0DFBC38F1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16383659385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16383659385.webp', 'https://www.flickr.com/photos/zaragozaantigua/16383659385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25613, 'Casas Baratas 1932', 'Detalle de la manzana 48, proyectada por Miguel â”œĂ¼ngel Navarro, de la urbanizaciâ”œâ”‚n de Casas Baratas del ensanche de Miralbueno, en el actual entorno de las calles de Sta. Teresa de Jesâ”œâ•‘s (frontal), Mariano Supervâ”œÂ¡a (traseras), y Luis Vives (derecha). Apenas subsisten unos pocos de los 21 originales hoteles unifamiliares. Los de la imagen, ciertamente no: casi todos en la reserva de la pequeâ”œâ–’a manzana de Ram de Viu- Mariano Supervâ”œÂ¡a-Bruno Solano. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.63894600, -0.89407700, '0101000020E6100000A662635E479CECBF7BF486FBC8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19324833871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19324833871.webp', 'https://www.flickr.com/photos/zaragozaantigua/19324833871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25617, 'Proyecto de ensanche 1923', 'Proyecto de zona de ensanche redactado. Plano de urbanizaciâ”œâ”‚n. Sociedad Rapid Cem Fer, Ayuntamiento de Zaragoza, junio de 1923. Orientado con el norte a la derecha, se trata del ensanche de Miralbueno. La plaza central proyectada corresponde a la llamada de Espaâ”œâ–’a, luego de San Francisco. Fuente: Zaragoza 1908-2008. Colegio Oficial de Arquitectos de Aragâ”œâ”‚n, 2009.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.64092800, -0.89485900, '0101000020E61000001D007157AFA2ECBF9C8BBFED09D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22146652259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22146652259.webp', 'https://www.flickr.com/photos/zaragozaantigua/22146652259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25619, 'La Ballena 2013', 'El colegio de las Hermanas Franciscanas del Espâ”œÂ¡ritu Santo de Montpellier se inaugurâ”œâ”‚ en 1948 en la calle Andrâ”œÂ®s Piquer 5 de Zaragoza. Tras la uniâ”œâ”‚n en 1979 con el colegio de los Hermanos de La Salle, en la calle Santa Teresa 23 (en la foto, al fondo), comienzan los cursos conjuntos en 1981. En 2013 se levanta un patio elevado sobre el preexistente, segâ”œâ•‘n proyecto de 2012 de Guzmâ”œĂ­n de Yarza, al que se da el nombre de La Ballena. Fuente visual: architizer255.rssing.com/', 2013, 2013, 2013, 'Siglo XXI', 'UNIVERSIDAD', 41.63971600, -0.89432400, '0101000020E610000097E4805D4D9EECBF2D5DC136E2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23857499073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23857499073.webp', 'https://www.flickr.com/photos/zaragozaantigua/23857499073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25631, 'Pl. de Espaâ”œâ–’a 1929', 'Manzana nâ”¬â•‘ 48 de las casas baratas del Huerva con baja densidad incluida en el ensanche de Miralbueno, entorno de la proyectada plaza de Espaâ”œâ–’a que luego terminarâ”œÂ¡a recibiendo el nombre de San Francisco. Esta imagen ha sido capturada durante la construcciâ”œâ”‚n de sus veintiuna viviendas unifamiliares promovidas en 1929 por la Sociedad Zaragozana de Urbanizaciâ”œâ”‚n y Construcciâ”œâ”‚n segâ”œâ•‘n proyecto del arquitecto Miguel â”œĂ¼ngel Navarro Pâ”œÂ®rez. Las de la escena se corresponden con las ocho viviendas pareadas del centro del tramo. La calle sin nombre de primer tâ”œÂ®rmino serâ”œÂ¡a denominada de Santa Teresa de Jesâ”œâ•‘s, entre las calles de Bruno Solano (al fondo) y Luis Vives. Ninguna de estas viviendas ha perdurado. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63855700, -0.89500900, '0101000020E6100000710514EAE9A3ECBFE1D05B3CBCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34395919764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34395919764.webp', 'https://www.flickr.com/photos/zaragozaantigua/34395919764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25632, 'GE Basilio Paraâ”œÂ¡so 1933', 'Imagen capturada durante la inauguraciâ”œâ”‚n oficial del grupo escolar Basilio Paraâ”œÂ¡so, sito al sureste de la zona de casas baratas del ensanche de Miralbueno, cerca del cauce del râ”œÂ¡o Huerva. La construcciâ”œâ”‚n y sustento de este colegio pâ”œâ•‘blico fue sufragado a la memoria del prâ”œâ”‚cer Basilio Paraâ”œÂ¡so por su hijo. La primera maestra nacional de este centro fue Asunciâ”œâ”‚n Magaâ”œâ–’a Pâ”œÂ®rez, y Mariano Gâ”œĂ­lvez el primer maestro. La imagen ha sido capturada desde un vial sin nombre que mâ”œĂ­s tarde serâ”œĂ­ denominado de Mariano Supervâ”œÂ¡a. A la lzquierda, un camino que luego sera incorporado como tramo final de la calle de Bruno Solano. Al inicio de la dâ”œÂ®cada de los aâ”œâ–’os setenta este edificio serâ”œĂ­ sustituido por uno nuevo, de cuatro alturas, en la misma ubicaciâ”œâ”‚n, que hoy sigue prestando servicio pâ”œâ•‘blico como CEIP Basilio Paraâ”œÂ¡so. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63854000, -0.89380700, '0101000020E6100000AAF23D23119AECBF0B98C0ADBBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35552281084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35552281084.webp', 'https://www.flickr.com/photos/zaragozaantigua/35552281084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22677, 'Condes de Aragâ”œâ”‚n 1976', 'Imagen, desde la notable atalaya del nâ”¬â•‘ 7 de la calle Luis Bermejo, con una interesante panorâ”œĂ­mica del explosivo crecimiento urbanâ”œÂ¡stico de la ciudad en la zona finalmente denominada "Romareda", aunque sin aâ”œâ–’adirle el adjetivo "Nueva" y diferenciarlo asâ”œÂ¡ del mâ”œĂ­s antiguo y cercano a la ciudad "barrio de la Romareda", inmediato a la estaciâ”œâ”‚n de Campo Sepulcro. Este es una de los grandes paradigmas de Zaragoza donde, por mâ”œĂ­gicas circunstancias, todas las cosas estâ”œĂ­n donde estâ”œĂ­n "asâ”œÂ¡, de toda la vida". En primer plano, el bloque del nâ”¬â•‘ 11 de la nueva calle Condes de Aragâ”œâ”‚n, que se nos revela a la izquierda como un periurbano vial, o portal entre dos mundos: el antiguo, con sus campos de herbâ”œĂ­ceas y cultivos rururbanos, y el moderno, con sus campos de espigados cultivos residenciales. Al fondo, a la derecha, destaca la mole del Hospicio Provincial del Alto de Carabinas. La Vâ”œÂ¡a de la Hispanidad aâ”œâ•‘n asemeja un lejano cinturâ”œâ”‚n de ronda, como cuando era la Carretera de los Enlaces. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.11 Sobre 87227', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63864500, -0.90502900, '0101000020E610000089CF9D60FFF5ECBF80608E1EBFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25873569584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25873569584.webp', 'https://www.flickr.com/photos/zaragozaantigua/25873569584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25721, 'Calle de Pradilla 1899', 'Sobre terrenos de la antigua Torre de Allustante, empinados por su inmediatez con el ascendente Camino de Torrero, la Sociedad de Propietarios "La Amistad" promoviâ”œâ”‚ en 1892 la parcelaciâ”œâ”‚n particular de una nueva barriada, y la urbanizaciâ”œâ”‚n de nuevos viales en una zona virgen. Fue denominado "Barrio de las Acacias", por los espinosos â”œĂ­rboles, aunque la socarronerâ”œÂ¡a indâ”œÂ¡gena enseguida sacâ”œâ”‚ punta al asunto, y lo rebautizâ”œâ”‚ "Barrio de los Chiflaos", porque no les cuadraba en la cabeza que gente de bien se subiera a vivir una zona cero glamurosa. Mâ”œĂ­s pronto que tarde, aun con chismorreos, fueron surgiendo nuevas calles como Vista Alegre, Sâ”œĂ­inz de Varanda, Marquâ”œÂ®s de Ahumada, y Pradilla, y en unas dâ”œÂ®cadas se podâ”œÂ¡an encontrar una cincuentena de casas de destacado porte, con amplios jardines, y con todos los servicios bâ”œĂ­sicos de la â”œÂ®poca. Como era una urbanizaciâ”œâ”‚n "particular", tenâ”œÂ¡a su guarda, y su cadena que, de noche, cerraba el acceso rodado. En la imagen, de muy mala calidad, porque la fuente no da para mejor cosa, vista de la calle Pradilla, con la calle Sâ”œĂ­inz de Varanda a la derecha. De la espectacularidad de esas fincas con torres, apenas queda un leve reflejo en unas pocas construcciones supervivientes, entre una mayorâ”œÂ¡a de nuevas, modernas y asâ”œÂ®pticas viviendas. Fuente: Revista "Nuevo Mundo", 1899.', 1899, 1899, 1899, 'Siglo XIX', 'UNIVERSIDAD', 41.63736000, -0.88348700, '0101000020E6100000EB1D6E878645ECBFA8E3310395D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19831895753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19831895753.webp', 'https://www.flickr.com/photos/zaragozaantigua/19831895753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25755, 'Parque Pignatelli 1990', 'Interior de la entrada al parque Pignatelli de Zaragoza, el 22 de marzo de 1990. Al fondo, paseo de Sagasta. A la izquierda, estatua de bronce con la inscripciâ”œâ”‚n "Los Ruiseâ”œâ–’ores". Ya no estâ”œĂ­. Fuente: "Memoria de las calles de Zaragoza", Juliâ”œĂ­n Ruiz Marâ”œÂ¡n, Librerâ”œÂ¡a General, 1998.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63881800, -0.88620200, '0101000020E610000019CBF44BC45BECBF4E0CC9C9C4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21683725031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21683725031.webp', 'https://www.flickr.com/photos/zaragozaantigua/21683725031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25777, 'Espacio Parque Pignatelli 1989', 'Imagen capturada en el interior del antiguo depâ”œâ”‚sito de agua soterrado de Pignatelli cuando era utilizado como escenario de la exposiciâ”œâ”‚n Ă”Ă‡Â£III Premio de Escultura Pablo GargalloĂ”Ă‡Ă˜. Este espacio fue diseâ”œâ–’ado por el arquitecto municipal Ricardo Magdalena en 1876 para depositar agua de boca y riego, con fâ”œĂ­brica de ladrillo, pilares de arenisca y bâ”œâ”‚veda que incluye hormigâ”œâ”‚n. De aquâ”œÂ¡ bajaba el agua que abastecâ”œÂ¡a, entre otras, la fuente de la Princesa o Neptuno. En 1983-87 este lugar fue intervenido para habilitarlo como municipal espacio expositivo (hasta 2006). En estos momentos (2017) se anuncia un ejecuciâ”œâ”‚n de un proyecto para estas instalaciones que supone la ampliaciâ”œâ”‚n del parque Pignatelli y mejorar la conexiâ”œâ”‚n viaria con el entorno, financiado con la construcciâ”œâ”‚n de 77 pisos de promociâ”œâ”‚n privada. Fuente visual: www.zaragoza.es/', 1989, 1989, 1989, 'Anos 80', 'UNIVERSIDAD', 41.63743400, -0.88625400, '0101000020E6100000B75F3E59315CECBFE2ADF36F97D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38074284835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38074284835.webp', 'https://www.flickr.com/photos/zaragozaantigua/38074284835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25784, 'Calle de Pradilla c.1895', 'Insâ”œâ”‚lita e impagable imagen capturada posiblemente desde la altura de la torre de Lacasa en el arranque de la calle de Vista Alegre, del original barrio de las Acacias, vulgo de los Chiflaos, urbanizado desde 1892 por la Sociedad de Propietarios La Amistad sobre terrenos de la antigua torre de Allustante. La calle de Pradilla, en descenso desde el camino de Torrero, se abre en el centro de la imagen para dar comienzo a la calle de Sâ”œĂ­inz de Varanda. Destaca el muestrario de la variopinta e irrepetible variedad de algunas de la 50 viviendas unifamiliares que conformaban esta barriada, todas con su correspondiente y apreciable zona ajardinada. Ninguna de ellas sobrevivirâ”œÂ¡a al devenir de los tiempos, sobre todo los de la segunda mitad de la centuria XX. Al fondo y a la derecha, feraz entorno de las torres de Catalina y de Monserrat, que flanqueaban el lado norte del camino de Lapuyade, o antigua Cabaâ”œâ–’era, paralelo al arbolado y mâ”œĂ­s alto cauce por donde fluâ”œÂ¡a al aire la nueva acequia del Plano, sobre el que emerge la neoclâ”œĂ­sica câ”œâ•‘pula de la iglesia de San Fernando,', 1895, 1895, 1895, 'Siglo XIX', 'UNIVERSIDAD', 41.63736000, -0.88348700, '0101000020E6100000EB1D6E878645ECBFA8E3310395D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49032889787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49032889787.webp', 'https://www.flickr.com/photos/zaragozaantigua/49032889787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25791, 'Paseo de Cuâ”œÂ®llar 1966', 'Imagen centrada en los inmuebles de los nâ”œâ•‘meros 15, 17 y 19 del paseo de Cuâ”œÂ®llar y el nâ”¬â•‘ 76 A de la calle de Vista Alegre, veteranos de principios del siglo XX asociados al barrio de Vista Alegre y con fachada principal a la subida de Cuâ”œÂ®llar. El nâ”¬â•‘ 15 fue proyectado por el arquitecto Julio Bravo Folch para oficinas y viviendas de la Sociedad Anâ”œâ”‚nima de Crâ”œÂ®dito y Seguros "La Regeneraciâ”œâ”‚n". A su derecha y tras el ingreso a un camino particular que conectaba descendente con el camino de las Alcachoferas, el edificio de oficinas de la Sociedad de Seguro Infantil "La Actividad", proyectado por el arquitecto Fâ”œÂ®lix Navarro Pâ”œÂ®rez. Chafaneando con la calle de Vista Alegre destaca el nâ”¬â•‘ 76 A de esa calle, resultado de la construcciâ”œâ”‚n en 1906, de un inmueble previo de 1894 derribado, con proyecto posiblemente por el arquitecto Josâ”œÂ® Marâ”œÂ¡a Pujol de Barberâ”œĂ­. Estos cuatro inmuebles fueron derribados a finales de 1968 y principio de 1969 para dar paso al actual bloque de viviendas con el numeral 15-17-19 del paseo de Cuâ”œÂ®llar y el bloque del nâ”¬â•‘ 1 de la calle de Vista Alegre, en coherencia con el bloque de los nâ”œâ•‘meros 9-11-13 del paseo que en la imagen y a la izquierda seâ”œâ–’ala el signo de los tiempos. En definitiva, otras excelentes muestras de la arquitectura local de comienzos del siglo XX desaparecidas de forma lamentable en beneficio del aprovechamiento vertical impersonal y descontextualizado.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63849200, -0.88439100, '0101000020E6100000390EBC5AEE4CECBFFA60191BBAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54384988668.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54384988668.webp', 'https://www.flickr.com/photos/zaragozaantigua/54384988668/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25927, 'P.â”¬â•‘ del General Mola c.1956', 'Luminosa imagen capturada desde cierta altura del tramo medio del paseo del General Mola, orientada en direcciâ”œâ”‚n norte, hacia la plaza de Paraâ”œÂ¡so, al fondo. En el lado de los impares, a la derecha, ya ha sido recrecido el original edificio de viviendas del nâ”¬â•‘ 37 (actual nâ”¬â•‘ 45), diseâ”œâ–’ado por Martâ”œÂ¡nez de Ubago para el conde de Monte Negrâ”œâ”‚n. Los hotelitos supervivientes, a uno y otro lado del paseo, seguirâ”œĂ­n esta tendencia uno a uno, bien por recrecimiento, bien por derribo y obra nueva. Desde el barrio de Venecia desciende, a la derecha, una composiciâ”œâ”‚n tranviaria motor-remolque de la serie 100, en servicio en la lâ”œÂ¡nea 5 (Venecia-Delicias). Fuente visual: www.ebay.es/', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34433725805.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34433725805.webp', 'https://www.flickr.com/photos/zaragozaantigua/34433725805/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26032, 'Camino de las Torres c.1945', 'Imagen capturada posiblemente desde la altura de la reciente torre del Sacrario Militare Italiano, que permite una interesante visual de las terrazas inferiores en descenso hacia la ciudad. En primerâ”œÂ¡simo plano, las enormes instalaciones de la fâ”œĂ­brica TUDOR, poco antes de trasladarse a la carretera de Navarra. De izquierda a derecha, el camino de las Torres, y la calle de Colâ”œâ”‚n, al frente, que arranca de Tenor Fleta. A la derecha, el antiguo camino de las Alcachoferas, y tras Tenor Fleta, los muros perimetrales del colegio de los PP. Agustinos, y la chimenea de la Lanera Aragonesa. En el paseo de las Damas, luminosa, la fachada del antiguo convento de las Oblatas. Y al fondo, visiâ”œâ”‚n panorâ”œĂ­mica de la ciudad vieja, con sus torres, câ”œâ•‘pulas, chimeneas, antes del estallido vertical. Fuente visual: Postal Garcâ”œÂ¡a Garrabella, en www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'UNIVERSIDAD', 41.63980700, -0.88512700, '0101000020E61000009ACFB9DBF552ECBF3D601E32E5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30943425895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30943425895.webp', 'https://www.flickr.com/photos/zaragozaantigua/30943425895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23678, 'Aerâ”œâ”‚dromo Sanjurjo 1938', 'Imagen capturada en el aerâ”œâ”‚dromo Sanjurjo de Zaragoza y centrada en un Heinkel He-51 C-1 de la alemana Legiâ”œâ”‚n Câ”œâ”‚ndor en curiosa situaciâ”œâ”‚n de "kopfstand bei vor landung", o capotado en aterrizaje. Este moderno biplano fue utilizado como aviâ”œâ”‚n de caza hasta la llegada de los soviâ”œÂ®ticos modelos Polikarpov I-15 e I-16 (denominados "Chato" y "Mosca", respectivamente) a las Fuerzas Aâ”œÂ®reas de la Repâ”œâ•‘blica Espaâ”œâ–’ola. Desde entonces fue encomendado a labores de aviâ”œâ”‚n de asalto o ataque al suelo. Fuente visual: www.todocoleccion.net', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38528391930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38528391930.webp', 'https://www.flickr.com/photos/zaragozaantigua/38528391930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26065, 'Campo de la Victoria 1938', 'Imagen capturada desde la altura de la tribuna montada en el Campo de la Victoria con motivo del festejo organizado el 19 de abril con motivo del aniversario del Decreto de Unificaciâ”œâ”‚n de FET y JONS, con presencia del general Francisco Franco. Este despejado panorama edilicio fue denominado temporalmente "Campo de la Victoria", en el ensanche de Miralbueno, entre la original plaza de Espaâ”œâ–’a y la prolongaciâ”œâ”‚n de la Gran Vâ”œÂ¡a hasta el parque de Buenavista y el râ”œÂ¡o Huerva. Al fondo y a la izquierda, las dos pioneras manzanas proyectadas por Secundino Zuazo que inauguraron el moderno desarrollo urbanâ”œÂ¡stico de esta zona. A la derecha, la mole del proyectado nuevo convento de los carmelitas descalzos de San Josâ”œÂ®, militarizado tras el 18 de julio de 1936 por el ramo militar de transmisiones. Junto a â”œÂ®l, algunas de las seriadas viviendas unifamiliares proyectadas por Miguel â”œĂ¼ngel Navarro dentro del proyecto de las Casas Baratas de Miralbueno. Al fondo se destacan la câ”œâ•‘pula de Santiago el Mayor, las dos torres y câ”œâ•‘pula central del templo del Pilar, y la torre de la Seo, ademâ”œĂ­s del mâ”œĂ­s cercano de la Previsiâ”œâ”‚n Social. Este gran espacio luego fue urbanizado y ordenado en nuevos viales denominados Bruno Solano, Andrâ”œÂ®s Piquer, Santa Teresa de Jesâ”œâ•‘s, y plaza de San Francisco, denominaciâ”œâ”‚n impuesta a la prevista plaza de Espaâ”œâ–’a como forma de solucionar la duplicidad una vez que a la antigua plaza de la Constituciâ”œâ”‚n el nuevo râ”œÂ®gimen le impuso esa denominaciâ”œâ”‚n. Entre el mar de corporativas camisas azules destaca, en el centro de la escena, la albina zona conformada por las enfermeras falangistas.', 1938, 1938, 1938, 'Anos 30', 'UNIVERSIDAD', 41.63956500, -0.89510600, '0101000020E61000000E828E56B5A4ECBF47551344DDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49972403028.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49972403028.webp', 'https://www.flickr.com/photos/zaragozaantigua/49972403028/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21501, 'Parque de Buena Vista 1927', 'Marâ”œÂ¡n Chivite. 1927. En Zaragoza tambiâ”œÂ®n la lluvia es pertinaz, y cuando se pone, se pone, como cuando hubo que retrasar la "Fiesta automovilista" de octubre de ese aâ”œâ–’o, despuâ”œÂ®s de los pilares, en terrenos "del que ha de ser futuro parque de Buena Vista" (sic). La cosa, organizada por la Real Asociaciâ”œâ”‚n Automovilista Aragonesa, consistiâ”œâ”‚ en una misa de campaâ”œâ–’a y en la bendiciâ”œâ”‚n ritual de todos y cada uno de los vehâ”œÂ¡culos asistentes. Fue una ceremonia de altura, con presencia del Capitâ”œĂ­n General de la Regiâ”œâ”‚n Militar, el Gobernador Civil, y el Alcalde. Celebrâ”œâ”‚ un delegado del Prelado de la ciudad, y una banda de mâ”œâ•‘sica sintonizâ”œâ”‚ ambiental mâ”œâ•‘sica sacra. Fue un â”œÂ®xito de crâ”œÂ¡tica y pâ”œâ•‘blico. En la imagen, aspecto del paseo central del futuro parque durante el desarrollo de la misa de campaâ”œâ–’a en la semirrotonda final del paseo. Los coches, ordenadicos a la izquierda, y al fondo, el Huerva, el reciente puente sobre su cauce, y poca cosa mâ”œĂ­s. En primer plano, rodilla en tierra del pâ”œâ•‘blico asistente, en lo que hoy es la fuente cibernâ”œÂ®tica y la parte baja de la escalinata de acceso al Cabezo de Buena Vista. Fuente: "Aragâ”œâ”‚n : revista grâ”œĂ­fica de cultura aragonesa" (Aâ”œâ–’o III, Nâ”¬â•‘ 26, noviembre 1927).', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15481681297.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15481681297.webp', 'https://www.flickr.com/photos/zaragozaantigua/15481681297/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21551, 'Cabezo de Buena Vista 1922', 'Foto: Julio Requejo. Instantâ”œĂ­nea en color tomada el 23 de enero de 1922 en el despuâ”œÂ®s Jardâ”œÂ¡n de Invierno del cabezo de Buena Vista de Zaragoza, con la gruta que encabezaba el paraje, entre las dos escaleras. Aunque el parque de Miguel Primo de Rivera se inaugurâ”œâ”‚ en 1929, el cabezo de Buena Vista era una zona de esparcimiento acondicionada desde hacâ”œÂ¡a dâ”œÂ®cadas. El lugar de la imagen ("La Gruta") fue el resultado del aprovechamiento de una gravera en la ladera del cabezo, convertida en refugio climâ”œĂ­tico en 1914. El aspecto actual se remonta a 1959. En primer plano, sentada en un banco, Rufina al sol, abrigada y elegante. Fuente visual: DARA/AHPZ.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20757916724.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20757916724.webp', 'https://www.flickr.com/photos/zaragozaantigua/20757916724/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21610, 'Parque de Buenavista 1927', 'Plano del "Nuevo parque" proyectado en el cabezo de Buenavista y las huertas que se extendâ”œÂ¡an a sus pies hasta el râ”œÂ¡o Huerva. Fue diseâ”œâ–’ado por el ingeniero Martâ”œÂ¡n Augusti. En 1929 fue inaugurado oficialmente por Miguel Primo de Rivera, que le dio su nuevo nombre. Fuente visual: www.flickr.com/photos/114031783@N02/', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.63445200, -0.89552300, '0101000020E6100000191BBAD91FA8ECBFDF701FB935D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29396651461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29396651461.webp', 'https://www.flickr.com/photos/zaragozaantigua/29396651461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22257, 'Fuente de Neptuno c.1966', 'En esta urbe, Neptuno ha sido durante varias dâ”œÂ®cadas, a su pesar, mercurial espectro pâ”œÂ®treo, errâ”œĂ­tico, volâ”œĂ­til, inestable, como recapitula Antonio Tausiet en tausiet.blogspot.com.es/2016/01/la-historia-errante-de-ne... La imagen capta su segunda juventud en el gran parque de la ciudad, aunque a su mâ”œÂ¡tica inmortalidad le importen bien poco las cosas de la edad. A la derecha, surge de la foresta la mole de la Casa Grande. Pero â”œÂ®l estâ”œĂ­ bien donde estâ”œĂ­, en redonda y acogedora plaza peatonal, en la imagen aâ”œâ•‘n sin palmeras, ni argentinas cotorras, aunque sâ”œÂ¡ con setos y parterres que hacen que el jardâ”œÂ¡n sea mâ”œĂ­s francâ”œÂ®s que inglâ”œÂ®s. En la actualidad el câ”œÂ®sped ha sustituido a los juegos florales. A la inmensa mayorâ”œÂ¡a zaragozana y forana le cae bien Neptuno, no en vano esta es una zona del parque donde se congrega mucha buena gente, prâ”œĂ­cticamente a todas las horas del dâ”œÂ¡a y aun la noche. Aunque de noche, algunas noches, descabezadas presencias enemigas la emprenden impunemente con el pobre Neptuno, y le quiebran los brazos, le roban el tridente, o se lo dejan averiado, sin poderes. Casi siempre, como consecuencia de los ataques, asemeja un dios que ya no rige ni gobierna sobre el acuâ”œĂ­tico mundo. Estâ”œĂ­ demediado, triste. Fuente: AYUNTAMIENTO DE ZARAGOZA/Archivo fotogrâ”œĂ­fico ARRIBAS/Noviembre 196?', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63573200, -0.89657600, '0101000020E6100000A41CCC26C0B0ECBFA5828AAA5FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665421250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665421250.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665421250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25937, 'Tranvâ”œÂ¡a Academia 1969', 'Imagen capturada en la terminal de la tranviaria lâ”œÂ¡nea 10/Academia junto a la Academia General MIlitar, y centrada en el coche articulado nâ”¬â•‘ 251, entrado en servicio en 1959 como resultado de la reconstrucciâ”œâ”‚n de los antiguos coches nâ”¬â•‘ 92-93, y que terminâ”œâ”‚ un par de aâ”œâ–’os despuâ”œÂ®s en el desguace. A la derecha, su conductor.', 1969, 1969, 1969, 'Anos 60', NULL, 41.69851100, -0.86877800, '0101000020E61000004A7F2F8507CDEBBFB972F6CE68D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51834665450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51834665450.webp', 'https://www.flickr.com/photos/zaragozaantigua/51834665450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21612, 'Cabezo de Buenavista 1923', 'Imagen centrada en el emplazamiento del Monumento al rey Alfonso I el Batallador en lo alto del Cabezo de Buenavista, durante las tareas de construcciâ”œâ”‚n del pedestal sobre el que poco despuâ”œÂ®s se habrâ”œÂ¡a de instalar la estatua en mâ”œĂ­rmol del cristiano monarca que conquistâ”œâ”‚ Saraqusta en 1118. Encargada en 1918 con motivo del centenario ocho de este evento, la estatua fue proyectada por el escultor Josâ”œÂ® Bueno. A comienzos de 1919 tuvo lugar el institucional acto de colocaciâ”œâ”‚n de la primera piedra del monumento, cuyo pedestal fue diseâ”œâ–’ado por el arquitecto Miguel â”œĂ¼ngel Navarro. La imagen fue realizada durante la instalaciâ”œâ”‚n del referido pedestal en la primavera de 1923, una entera legislatura despuâ”œÂ®s, y se habrâ”œÂ¡a tomado levemente escorada hacia la izquierda del frontal del monumento. Finalizado ya el escalonado pedestal y el prismâ”œĂ­tico cuerpo inferior, se estaba comenzando a encajar las piedras del cuerpo cilâ”œÂ¡ndrico sobre el que se habrâ”œÂ¡a de colocar la estatua en octubre de ese aâ”œâ–’o. En 1927 se instalâ”œâ”‚ finalmente el brocâ”œÂ¡neo leâ”œâ”‚n previsto, procedente de los talleres Averly. No consta que hubiera oficial inauguraciâ”œâ”‚n del monumento, tal vez por haberse dilatado tanto su terminaciâ”œâ”‚n respecto del evento al que se asociaba. En el Archivo Histâ”œâ”‚rico Provincial de Zaragoza esta imagen todavâ”œÂ¡a se nos presenta referenciada con el desconcertante tâ”œÂ¡tulo: "Grupo de siete personas en la calle, bajo la torre mudâ”œÂ®jar de una iglesia, junto con un burro", y con el descriptor "Escenas rurales". Fuente visual: Archivo Gabriel Faci Abad, en AHPZ', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63366800, -0.89337000, '0101000020E6100000D847A7AE7C96ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31141022308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31141022308.webp', 'https://www.flickr.com/photos/zaragozaantigua/31141022308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21613, 'C.â”¬â•‘ de los Cubos c.1920', 'Posible posado de Manuel Hernâ”œĂ­ndez, hijo de Gregorio Hernâ”œĂ­ndez, seguramente autor de la foto, dueâ”œâ–’o de la fâ”œĂ­brica de sombreros de la derecha, junto al brazal Bajo de la acequia de la Romareda, entre el Camino de los Cubos y el râ”œÂ¡o Huerva, muy cerca del punto donde unos aâ”œâ–’os despuâ”œÂ®s comenzarâ”œĂ­ el cubrimiento del primer tramo urbano de este râ”œÂ¡o. Al fondo se ve la câ”œâ•‘pula de la iglesia de Santiago, y una torre del Pilar. A la espalda del fotâ”œâ”‚grafo, la trinchera del ferrocarril de Zaragoza a Barcelona.', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.64455700, -0.89106400, '0101000020E6100000FF9254A69883ECBF35B401D880D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31144527820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31144527820.webp', 'https://www.flickr.com/photos/zaragozaantigua/31144527820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21676, 'Ampliaciâ”œâ”‚n suroeste 1932', 'Vista aâ”œÂ®rea de la Gran Vâ”œÂ¡a. En la esquina superior izquierda, el paseo de Sagasta. En la superior derecha, la prevista plaza de Espaâ”œâ–’a. En el centro, el recinto ferial habilitado durante las fiestas mayores de octubre. Al comienzo de la Gran Vâ”œÂ¡a, la explanada de los Campos Elâ”œÂ¡seos, con los restos del antiguo velâ”œâ”‚dromo. Y cruzando en curva, la trinchera del tren sin cubrir.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.64411200, -0.89184400, '0101000020E61000004948A46DFC89ECBF077B134372D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14846214539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14846214539.webp', 'https://www.flickr.com/photos/zaragozaantigua/14846214539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21697, 'Plaza de Espaâ”œâ–’a aâ”œâ–’os 30', 'Grupo de chavales jugando al fâ”œâ•‘tbol en una explanada en el entorno de la proyectada plaza de Espaâ”œâ–’a. Al fondo a la derecha, edificio de viviendas entre las calles de las Cortes de Aragâ”œâ”‚n y de Baltasar Graciâ”œĂ­n. El edificio formaba parte del proyecto de ensanche de Miralbueno de 1928, como manzana de "Casas Baratas". Fue proyectado por Zuazo, Navarro y Ribas, y construido en 1930.', 1930, 1930, 1939, 'Anos 30', 'UNIVERSIDAD', 41.64065500, -0.89426500, '0101000020E610000059A31EA2D19DECBF6B82A8FB00D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15465921496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15465921496.webp', 'https://www.flickr.com/photos/zaragozaantigua/15465921496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21745, 'Gran Vâ”œÂ¡a 1931', 'Durante la madrugada del 19 de marzo, se declarâ”œâ”‚ un incendio en la fâ”œĂ­brica de sombreros de Manuel Hernâ”œĂ­ndez y Compaâ”œâ–’â”œÂ¡a, localizada en el camino de los Cubos nâ”¬â•‘ 275. Edificio, instalaciones y maquinaria quedaron en situaciâ”œâ”‚n de siniestro total, y los cien obreros empleados, sin trabajo. Esta antigua fâ”œĂ­brica formaba parte del complejo industrial de Miralbueno, entre el Camino de los Cubos y la acequia de la Romareda a un lado, una pronunciada curva del râ”œÂ¡o Huerva a sus espaldas, y la vâ”œÂ¡a del ferrocarril MZA. Muy cerca quedaba la fâ”œĂ­brica de espejos "La Veneciana", la de aparatos de precisiâ”œâ”‚n "Amado Laguna de Rins", "Fundiciâ”œâ”‚n Pellicer y Juan", "fâ”œĂ­brica de hielo Archanco"... El cubrimiento del râ”œÂ¡o Huerva en su tramo urbano, unos aâ”œâ–’os antes, habâ”œÂ¡a puesto a esta fâ”œĂ­brica en un aprieto, pues quedaba casi en medio de la proyectada y espaciosa nueva "Gran Vâ”œÂ¡a", que se detenâ”œÂ¡a justo en sus inmediaciones. La imagen tras el incendio estâ”œĂ­ capturada, precisamente, desde la Gran Vâ”œÂ¡a. En la parte superior derecha, apenas queda en pie la parte del muro con la "S" final del gran râ”œâ”‚tulo "Fâ”œĂ­brica de sombreros". Declarada en ruina, fue derribada tiempo despuâ”œÂ®s. La urbanizaciâ”œâ”‚n de la Gran Vâ”œÂ¡a continuâ”œâ”‚, como "paseo de Fernando el Catâ”œâ”‚lico", y a comienzos de la dâ”œÂ®cada de los 50 del pasado siglo, en los restos de su solar se levantâ”œâ”‚ una nueva manzana de viviendas. Fuente visual: Foto Palacio ("La Uniâ”œâ”‚n Ilustrada", Mâ”œĂ­laga).', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.64472200, -0.89110300, '0101000020E610000076C24B70EA83ECBF8081204086D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21880500090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21880500090.webp', 'https://www.flickr.com/photos/zaragozaantigua/21880500090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21747, 'Casas Baratas Miralbueno 1935', 'Imagen del proyectado conjunto iglesia-convento de los carmelitas descalzos, desde el interior de una de las manzanas con nuevas viviendas baratas de la Sociedad Zaragozana de Urbanizaciâ”œâ”‚n y Construcciâ”œâ”‚n, junto al Huerva, en el ensanche de Miralbueno. A la izquierda, las casas recayentes al vial luego denominado "Sta. Teresa de Jesâ”œâ•‘s". Al fondo, las de la calle "Agustâ”œÂ¡n de Quinto". A la derecha, las traseras de "Ram de Viu". De las originales 13 casas proyectadas para esta manzana, subsisten de alguna forma 7 de ellas. Fuente: Foto Marâ”œÂ¡n Chivite, "Mundo Grâ”œĂ­fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63962300, -0.89376400, '0101000020E6100000D8F2CAF5B699ECBF7C629D2ADFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22002804332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22002804332.webp', 'https://www.flickr.com/photos/zaragozaantigua/22002804332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21748, 'Bruno Solano 1935', 'Imagen de conjunto de una manzana de recientes viviendas de la Sociedad Zaragozana de Urbanizaciâ”œâ”‚n y Construcciâ”œâ”‚n, levantadas en 1928 junto al Huerva, en el ensanche de Miralbueno, segâ”œâ•‘n proyecto de Miguel â”œĂ¼ngel Navarro y Secundino Zuazo. Estaba ubicada en una nueva zona de urbanizaciâ”œâ”‚n de la ciudad, en torno a una gran plaza denominada "de Espaâ”œâ–’a", en cuyas proximidades se estaba construyendo el Campus Universitario. En este caso, la imagen captura la manzana 44, proyectada por Zuazo, y delimitada por los viales luego denominados "Bruno Solano", que cruza en primer plano de derecha a izquierda; "Sta. Teresa de Jesâ”œâ•‘s", enfrente, por el que se accede a las viviendas"; "Agustâ”œÂ¡n de Quinto", a la izquierda,entre las viviendas y el malogrado complejo conventual de los Carmelitas Descalzos; y Ram de Viu, por las traseras. De las originales 13 casas proyectadas para esta manzana, subsisten (de alguna forma) 7 de ellas. Fuente: Foto Marâ”œÂ¡n Chivite, "Mundo Grâ”œĂ­fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63945200, -0.89420500, '0101000020E6100000056EDDCD539DECBF4FAE2990D9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22016210835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22016210835.webp', 'https://www.flickr.com/photos/zaragozaantigua/22016210835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
